    List<String> keyTerms, List<Map> timeline, List<Map> people, List<Map> places,
    List<Map> mcq, List<Map> vs, List<Map> shortQs, List<Map> evalQs, List<Map> explQs,
    List<Map> causeEffect, List<Map> flashCards) {
  
  String simpleBreakdown = summary.split('।').where((s) => s.trim().isNotEmpty).take(5).map((s) => "'${escape(s.trim())}'").join(',\n        ');
  
  return '''
