    'key_terms': [
      ${keyTerms.map((t) => "{'term': '${escape(t['term'])}', 'meaning': '${escape(t['meaning'])}', 'example': '${escape(t['example'])}'}").join(',\n      ')},
    ],
    'people': [
      ${people.map((p) => "{'name': '${escape(p['name'])}', 'title': '${escape(p['title'])}', 'contribution': '${escape(p['contribution'])}', 'exam_importance': '${escape(p['exam_importance'])}'}").join(',\n      ')},
    ],
    'places': [
      ${places.map((p) => "{'name': '${escape(p['name'])}', 'description': '${escape(p['description'])}', 'significance': '${escape(p['significance'])}'}").join(',\n      ')},
    ],
    'timeline': [
