    ],
    'mnemonics': [
      {'formula': 'NEPO: N-Napoleon, E-Empire, P-Peace, O-Order', 'trick': 'নেপোলিয়ানের চারটি লক্ষ্য'},
      {'formula': 'CODE = Civil, Online (Criminal), Business (Commercial)', 'trick': 'কোড নেপোলিয়ানের তিনটি অংশ'},
    ],
    'timeline_table': [
      {'date': '১৭৬৯', 'event': 'নেপোলিয়ানের জন্ম', 'type': 'জন্ম'},
      {'date': '১৭৯৬', 'event': 'ইটালি অভিযান', 'type': 'সামরিক'},
