      {'date': '১৮০৪', 'event': 'কোড নেপোলিয়ান, সম্রাট', 'type': 'রাজনৈতিক'},
      {'date': '১৮০৫', 'event': 'উলম, অস্টারলিজ, ট্রাফালগার', 'type': 'সামরিক'},
      {'date': '১৮০৬', 'event': 'মহাদেশীয় অবরোধ', 'type': 'অর্থনৈতিক'},
