void main() {
  print('Building Chapter 2 seed file...');
  
  // ===== 2.1 নেপোলিয়ান বোনাপার্টের ক্ষমতালাভ =====
  var t1 = buildTopic('chapter2_topic_1', 'নেপোলিয়ান বোনাপার্টের ক্ষমতালাভ', 1, 
    // summary
    'নেপোলিয়ান বোনাপার্ট ১৭৬৯ সালে কর্সিকা দ্বীপে জন্মগ্রহণ করেন। ১৭৮৬ সালে তিনি ফরাসি গোলন্দাজ বাহিনীতে সহকারী লেফটেন্যান্ট পদে যোগ দেন। ১৭৯৩ সালে তুলোঁ বন্দরকে ব্রিটিশ অবরোধমুক্ত করার পুরস্কারস্বরূপ তিনি ব্রিগেডিয়ার পদে উন্নীত হন। ১৭৯৫ সালে একদল উন্মত্ত জনতার আক্রমণ থেকে ন্যাশনাল কনভেনশনকে রক্ষা করে তিনি মেজর জেনারেল পদ লাভ করেন। তিনি ১৭৯৬ সালে ইটালি অভিযানে অভূতপূর্ব সাফল্য লাভ করেন এবং ক্যাম্পোফরমিয়োর সন্ধি স্বাক্ষর করেন। ১৭৯৮ সালে তিনি মিশর অভিযানে যান। ১৭৯৯ সালের ৯ নভেম্বর তিনি সামরিক অভ্যুত্থান ঘটিয়ে ডাইরেক্টরির শাসনের অবসান ঘটান এবং কনসুলেট শাসনব্যবস্থা প্রবর্তন করেন। ১৮০২ সালে তিনি আজীবনের জন্য কনসাল পদ অধিকার করেন এবং ১৮০৪ সালে নিজেকে ফরাসি সম্রাট ঘোষণা করেন।',
    // voiceScript
    'প্রিয় ছাত্রছাত্রীরা, আজ আমরা আলোচনা করব ফরাসি বিপ্লবের পরবর্তী সময়ের সবচেয়ে গুরুত্বপূর্ণ ব্যক্তি — নেপোলিয়ান বোনাপার্টের ক্ষমতালাভ নিয়ে। নেপোলিয়ানের জীবন ছিল এক বিস্ময়কর ও অবিশ্বাস্য উত্তরণের কাহিনি। এক সাধারণ সৈনিক থেকে রাজরক্ত ছাড়াই ফ্রান্সের সম্রাট পদে তাঁর আসীন হওয়া ইতিহাসে বিরল।\n\nপ্রথমেই জানব নেপোলিয়ানের প্রাথমিক জীবন সম্পর্কে। তিনি ১৭৬৯ সালের ১৫ আগস্ট ভূমধ্যসাগরের কর্সিকা দ্বীপের এক অতি সাধারণ পরিবারে জন্মগ্রহণ করেন। মাত্র সতেরো বছর বয়সে, অর্থাৎ ১৭৮৬ সালে তিনি ফরাসি গোলন্দাজ বাহিনীতে সহকারী লেফটেন্যান্ট পদে যোগ দেন। এটাই ছিল তাঁর সামরিক জীবনের সূচনা।\n\n১৭৯৩ সালে তুলোঁ বন্দরে একটি গুরুত্বপূর্ণ ঘটনা ঘটে। ব্রিটিশ বাহিনী তুলোঁ বন্দর অবরোধ করেছিল। নেপোলিয়ান দক্ষতার সাথে এই অবরোধ মুক্ত করেন। এই সাফল্যের পুরস্কারস্বরূপ তিনি ব্রিগেডিয়ার পদে উন্নীত হন। এরপর ১৭৯৫ সালে আরেকটি গুরুত্বপূর্ণ ঘটনা ঘটে। একদল উন্মত্ত জনতা ন্যাশনাল কনভেনশন আক্রমণ করলে নেপোলিয়ান সেই আক্রমণ থেকে কনভেনশনকে রক্ষা করেন। এই কাজের জন্য তিনি মেজর জেনারেল পদ লাভ করেন।\n\nনেপোলিয়ান নিজের যোগ্যতায় যেমন প্রধান সেনাপতি পদে আসীন হন, তেমনি ডাইরেক্টরি শাসনের দুর্বলতা তাঁকে ফ্রান্সে ক্ষমতার সর্বোচ্চ সীমায় উত্তরণে সহায়ক হয়। ডাইরেক্টরির শাসনকালে ফ্রান্স অভ্যন্তরীণ ও বৈদেশিক উভয় ক্ষেত্রে সংকটের মধ্যে পড়ে। ইংল্যান্ড, অস্ট্রিয়া, সার্ডিনিয়া ফ্রান্সের বিরুদ্ধে যুদ্ধে লিপ্ত ছিল।\n\nনেপোলিয়ান এই শক্তিজোটের বিরুদ্ধে একজন সমরনেতা হিসেবে অভূতপূর্ব সাফল্য লাভ করেন। তিনি ১৭৯৬ সালে ইটালিকে পরাজিত করে পার্মা, মডেলনা ও নেপলস এবং অস্ট্রিয়াকে পরাজিত করে মিলান দখল করেন। অতঃপর পোপের রাজ্য আক্রমণ করলে পোপ ষষ্ঠ পায়াস ও নেপোলিয়ানের মধ্যে স্বাক্ষরিত হয় টলেন্টিনোর সন্ধি — ১৯ ফেব্রুয়ারি, ১৭৯৭। অস্ট্রিয়ার আর্চ ডিউক চার্লস নেপোলিয়ানের সঙ্গে ক্যাম্পোফরমিয়োর সন্ধি স্বাক্ষরে বাধ্য হন — ১৭ অক্টোবর, ১৭৯৭। এই সন্ধির শর্তানুসারে, বেলজিয়ামের বৃহদাংশ, করফু এবং অ্যাড্রিয়াটিক সাগরের তীরবর্তী একাধিক দ্বীপপুঞ্জসহ অস্ট্রিয়ার বেশকিছু প্রদেশ ফ্রান্স দখল করে। ফ্রান্সের সীমা ব্যাপকভাবে প্রসারিত হয়।\n\nএই সাফল্যের ফলে ইউরোপে নেপোলিয়ানের জনপ্রিয়তা ব্যাপকভাবে বৃদ্ধি পায়। এরপর তিনি ইংল্যান্ডের বিরুদ্ধে মিশর অভিযানে অগ্রসর হন। সেখানে পিরামিডের যুদ্ধে — ১৭৯৮ — নেপোলিয়ান সাফল্য লাভ করলেও নীলনদের যুদ্ধে — ১৭৯৮ — ব্রিটিশ সেনাপতি নেলসনের কাছে পরাজিত হন। এই যুদ্ধে ফ্রান্সের নৌশক্তির দুর্বলতা প্রমাণিত হয়। কিন্তু এই পরাজয় তাঁর জনপ্রিয়তায় ও উত্তরণে বাধা হয়ে দাঁড়ায়নি। কারণ এই পরাজয়ের সংবাদ ফ্রান্সে পৌঁছোনোর আগেই তিনি দেশে চলে এসেছিলেন।\n\nঅভ্যন্তরীণ ক্ষেত্রে এসময় ডাইরেক্টরির অপশাসনে ফরাসি জনগণ ক্রমশ ক্ষুব্ধ হয়ে উঠছিল আর নেপোলিয়ানের জনপ্রিয়তা ক্রমে বৃদ্ধি পাচ্ছিল। সকলেই চাইছিল নেপোলিয়ানের মতো একজন দক্ষ শাসক দেশের শাসনভার গ্রহণ করুক। অ্যাবে সিয়েস এবং ব্যারাস নামক দুজন ডাইরেক্টরের সহায়তায় ১৭৯৯ সালের ৯ নভেম্বর এক সামরিক অভ্যুত্থান ঘটিয়ে নেপোলিয়ান ফ্রান্সে ডাইরেক্টরির শাসনের অবসান ঘটান।\n\nতাঁর নেতৃত্বে কনসুলেট নামক নতুন শাসনব্যবস্থার প্রবর্তন হয়। কনসুলেট শাসনের প্রথম কনসাল হন নেপোলিয়ান। বাকি দুই কনসাল হলেন অ্যাবে সিয়েস ও রজার ডুকো। প্রথম তথা প্রধান কনসাল রূপে তাঁর হাতে শাসনবিভাগের সর্বোচ্চ ক্ষমতা অর্পিত হয়। প্রথম ১০ বছরের জন্য কনসাল থাকলেও ১৮০২ সালে সংবিধান সংস্কার করে তিনি আজীবনের জন্য কনসাল পদ অধিকার করেন। ঐতিহাসিক কোবানের মতে, কনসুলেটের শাসনের ইঞ্জিন ও বাষ্প দুইই ছিলেন নেপোলিয়ান।\n\n১৮০৪ সালে মাত্র ৩৫ বছর বয়সে সিনেটের এক প্রস্তাবক্রমে তিনি গণভোটের মাধ্যমে নিজেকে ফরাসি জাতির সম্রাট হিসেবে ঘোষণা করেন। পোপের উপস্থিতিতে তিনি সম্রাটের মুকুট গ্রহণ করেন। এইভাবে ফ্রান্স তথা ইউরোপে শুরু হয় নেপোলিয়ানের যুগ — Age of Napoleon, ১৭৯৯-১৮১৪ খ্রিস্টাব্দ।\n\nপরের পাঠে আমরা জানব কোড নেপোলিয়ান সম্পর্কে, যা তাঁর আরেক গুরুত্বপূর্ণ অবদান।',
